create table product_images
(
    Id          int identity
        constraint PK_product_images
            primary key,
    product_id  uniqueidentifier
        constraint FK_product_images_products_product_id
            references products,
    image_url   nvarchar(255)                                   not null,
    created_at  datetime2 default '0001-01-01T00:00:00.0000000' not null,
    deleted_at  datetime2,
    modified_at datetime2,
    IsActive    bit       default CONVERT([bit], 0)             not null
)
go

create index IX_product_images_product_id
    on product_images (product_id)
go

